INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Shadowmasters Exile', 'Forgotten Realms - Heroes of Faerun', 'Ability Score: Dexterity, Intelligence, Charisma
INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Zhentarim Mercenary', 'Forgotten Realms - Heroes of Faerun', 'Tool Proficiency: Forgery Kit
INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Haunted One', 'Ravenloft - The Horrors Within', 'You are haunted by the events of your past. Whether it was a lone terrible incident or an accumulation of painful moments, you bear the unshakable weight of what happened to you. You’ve tried to bury it and run away from it, to no avail; it can’t be slain with a sword or banished via magic. Nevertheless, you persist.', 'Constitution, Wisdom, Charisma Feat: Survivor or a Dark Gift feat of your choice Skill Proficiencies: Arcana and Survival Tool Proficiencies: Choose one kind of Gaming Set Equipment: Choose A or B: (A) Gaming Set (same as above), Crowbar, Holy Water (1 flask), Mirror, Oil(2 flasks), Signal Whistle, Tinderbox, Traveler’s Clothes, 5 Torches, Waterskin, and 14 GP; or (B) 50 GP', '', '', '', '', FALSE, ARRAY['ravenloft', 'rthw']::TEXT[]) ON CONFLICT (name) DO UPDATE SET source = EXCLUDED.source, description = EXCLUDED.description, ability_scores = EXCLUDED.ability_scores, feat = EXCLUDED.feat, skill_proficiencies = EXCLUDED.skill_proficiencies, tool_proficiencies = EXCLUDED.tool_proficiencies, equipment = EXCLUDED.equipment, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Investigator', 'Ravenloft - The Horrors Within', 'You relentlessly seek the truth. Perhaps you witnessed something remarkable or terrible and now desire to unravel its mystery, or maybe you’re motivated by universal justice and honesty. Whether the cases you’re embroiled in are local crimes or eldritch conspiracies, you’re driven to reveal what others would keep hidden.', 'Intelligence, Wisdom, Charisma Feat: Sharp Eye or a Dark Gift feat of your choice Skill Proficiencies: Insight and Investigation Tool Proficiencies: Disguise Kit Equipment: Choose A or B: (A) Disguise Kit, Manacles, Shovel, Traveler’s Clothes, 3 Vials, and 16 GP; or (B) 50 GP', '', '', '', '', FALSE, ARRAY['ravenloft', 'rthw']::TEXT[]) ON CONFLICT (name) DO UPDATE SET source = EXCLUDED.source, description = EXCLUDED.description, ability_scores = EXCLUDED.ability_scores, feat = EXCLUDED.feat, skill_proficiencies = EXCLUDED.skill_proficiencies, tool_proficiencies = EXCLUDED.tool_proficiencies, equipment = EXCLUDED.equipment, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Mist Wanderer', 'Ravenloft - The Horrors Within', 'You once knew your home. But one day, the Mists rose and drew you into a Domain of Dread. Ever since, you have wandered between domains, braving the mercurial Mists as you search for a way home. Your time in these cursed realms has changed you, yet you find solace in communities of fellow wanderers throughout the Mists.', 'Dexterity, Constitution, Wisdom Feat: A Dark Gift feat of your choice (see “Feats” later in this chapter; Mist Walker is recommended) Skill Proficiencies: Survival and Stealth Tool Proficiencies: Choose one kind of Artisan’s Tools Equipment: Choose A or B: (A) Artisan’s Tools (same as above), Lamp, Oil (5 flasks), Pouch, Rope, Tinderbox, Traveler’s Clothes, and 30 GP; or (B) 50 GP', '', '', '', '', FALSE, ARRAY['ravenloft', 'rthw']::TEXT[]) ON CONFLICT (name) DO UPDATE SET source = EXCLUDED.source, description = EXCLUDED.description, ability_scores = EXCLUDED.ability_scores, feat = EXCLUDED.feat, skill_proficiencies = EXCLUDED.skill_proficiencies, tool_proficiencies = EXCLUDED.tool_proficiencies, equipment = EXCLUDED.equipment, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Spirit Medium', 'Ravenloft - The Horrors Within', 'Through strange rituals and fateful encounters, you’ve discovered that you bear a unique connection to the spirits of the dead and damned. Your body is a conduit for such spirits, granting you prescient insight from beyond. But these spirits’ intentions aren’t always innocent, and their gifts come at a haunting cost.', 'Constitution, Intelligence, Wisdom Feat: Dark Gift feat of your choice (see “Feats”; Gathered Whispers is recommended) Skill Proficiencies: Insight and Religion Tool Proficiencies: Choose one kind of Gaming Set Equipment: Choose A or B: (A) Dagger, Gaming Set (same as above), Basket, Bell, 8 Candles, Ink, Ink Pen, Paper (5 sheets), Tinderbox, Traveler’s Clothes, and 32 GP; or (B) 50 GP', '', '', '', '', FALSE, ARRAY['ravenloft', 'rthw']::TEXT[]) ON CONFLICT (name) DO UPDATE SET source = EXCLUDED.source, description = EXCLUDED.description, ability_scores = EXCLUDED.ability_scores, feat = EXCLUDED.feat, skill_proficiencies = EXCLUDED.skill_proficiencies, tool_proficiencies = EXCLUDED.tool_proficiencies, equipment = EXCLUDED.equipment, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
