INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Carouser', 'Astarion''s Book of Hungers', 'Tool Proficiency: Choose one kind of Gaming Set
INSERT INTO official.backgrounds (name, source, description, ability_scores, feat, skill_proficiencies, tool_proficiencies, equipment, legacy, tags) VALUES ('Pact Seeker', 'D&D Beyond Drops - May 2026', 'You had a purpose in mind. Perhaps you were seeking out knowledge or power. Or maybe you were in search of hidden secrets. One way or another, your journey lead you to seek out an extraplanar entity. Once you made contact, a deal was struck, and your life changed.', 'Constitution, Intelligence, Charisma Feat: Choose one Planar Pact feat Skill Proficiencies: Arcana and Persuasion Tool Proficiencies: Calligrapher’s Supplies Equipment: Choose A or B: (A) Book, Calligrapher’s Supplies, Ink, Ink Pen, Parchment (10 sheets), Traveler’s Clothes, 2 GP; or (B) 50 GP.', '', '', '', '', FALSE, ARRAY['drops', 'drops0526', 'exotic']::TEXT[]) ON CONFLICT (name) DO UPDATE SET source = EXCLUDED.source, description = EXCLUDED.description, ability_scores = EXCLUDED.ability_scores, feat = EXCLUDED.feat, skill_proficiencies = EXCLUDED.skill_proficiencies, tool_proficiencies = EXCLUDED.tool_proficiencies, equipment = EXCLUDED.equipment, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
